changeSet.sql:
-- Alter language constants
ALTER TYPE LanguageConstantScopeType RENAME TO LanguageConstantScopeType__;
CREATE TYPE LanguageConstantScopeType as ENUM ('UI', 'ADMIN', 'SERVER', 'HINTS', 'ANDROID_CLIENT', 'IOS_CLIENT', 'HELP', 'MENU', 'DASHBOARD');
ALTER TABLE language_constants ALTER COLUMN scope type LanguageConstantScopeType using scope::text::LanguageConstantScopeType;
DROP TYPE LanguageConstantScopeType__;

UPDATE language_constants SET scope = 'DASHBOARD' WHERE name LIKE 'DASHBOARD%' AND scope = 'SERVER';
UPDATE language_constants SET scope = 'DASHBOARD', name = 'DASHBOARDS$AUDIT$AUDIT' WHERE name = 'AUDIT$AUDIT';
